const item = $input.item.json;

const diasRestantes = parseFloat(item.dias_restantes);
const titulo = item.titulo || 'Imóvel';
const sublista = item.sublista || '';
const grupo = item.grupo || '';
const link = item.link_leilao || '';

// Formatar data/hora do leilão
const dueDateUTC = new Date(item.due_date);
const dataFormatada = dueDateUTC.toLocaleDateString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  weekday: 'long',
  day: '2-digit',
  month: 'long',
  year: 'numeric'
});
const horaFormatada = dueDateUTC.toLocaleTimeString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  hour: '2-digit',
  minute: '2-digit'
});

// Truncar título longo
const tituloResumido = titulo.length > 100 
  ? titulo.substring(0, 100) + '...' 
  : titulo;

// Definir tipo de lembrete e emoji
let tipoLembrete, emoji, urgencia;

if (diasRestantes >= 1.9 && diasRestantes <= 2.1) {
  tipoLembrete = '2 DIAS';
  emoji = '📅';
  urgencia = 'Prepare a documentação e análise!';
} else if (diasRestantes >= 0.9 && diasRestantes <= 1.1) {
  tipoLembrete = '1 DIA';
  emoji = '⚠️';
  urgencia = 'AMANHÃ! Confirme participação.';
} else {
  tipoLembrete = 'HOJE';
  emoji = '🔨';
  urgencia = 'LEILÃO HOJE! Acesse agora.';
}

// Montar mensagem WhatsApp
const mensagem = [
  `${emoji} *LEMBRETE DE LEILÃO — ${tipoLembrete}*`,
  ``,
  `🏠 *Imóvel:*`,
  `${tituloResumido}`,
  ``,
  `📋 *Lista:* ${grupo} › ${sublista}`,
  `📆 *Data:* ${dataFormatada}`,
  `🕐 *Horário:* ${horaFormatada}`,
  ``,
  `⚡ ${urgencia}`,
  ``,
  link ? `🔗 *Link do leilão:*\n${link}` : '',
  ``,
  `_FlowDesck — Sistema de Gestão de Leilões_`
].filter(Boolean).join('\n');

return {
  json: {
    ...item,
    mensagem,
    tipoLembrete,
    dataFormatada,
    horaFormatada,
    tituloResumido
  }
};
